@startuml
skinparam packageStyle rectangle
skinparam classAttributeIconSize 10
skinparam classFontStyle italic
skinparam classBackgroundColor #F0F0F0
skinparam classBorderColor #000000
skinparam interfaceBackgroundColor #E0E0FF
skinparam interfaceBorderColor #000000
skinparam stereotypeCBackgroundColor #C0FFC0
skinparam stereotypeCBorderColor #000000
skinparam stereotypeIBackgroundColor #D0D0FF
skinparam stereotypeIBorderColor #000000

package "org" {
    package "steg" {
        package "jsa" {
            interface "SteganographyTechnique" {
                + embed(Message, Key, Cover): Stego
                + extract(Stego, Key): Message
            }
            class "AbstractSteganography" {
            }
            SteganographyTechnique <|-- AbstractSteganography
        }
        package "audio" {
            class "AdaptiveAudioSteganography" {
            }
            class "AudioLSBSteganography" {
            }
            AdaptiveAudioSteganography ..|> SteganographyTechnique
            AudioLSBSteganography ..|> SteganographyTechnique
        }
        package "image" {
            class "ImageLSBSteganography" {
            }
            ImageLSBSteganography ..|> SteganographyTechnique
        }
        package "video" {
            class "VideoSteganography" {
            }
            VideoSteganography ..|> SteganographyTechnique
        }
    }
}
@enduml
